    id: 'module-012',
    title: 'Building Your Client Relationship',
    slug: 'building-your-client-relationship',
    description: 'The quality of the client relationship determines the quality of the engagement. This module covers the specific practices that build trust, manage expectations, and create the conditions for excellent delivery.',
    audience: 'consultant',
